26→		}
27→
28→		w.Header().Set("Content-Type", "application/json")
29→		w.WriteHeader(http.StatusOK)
30→		_ = json.NewEncoder(w).Encode(Response{OK: true, DBOK: dbOK})
31→	}
32→}
