  1→package httpx
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"net"
  7→	"net/http"
  8→	"os"
  9→	"strconv"
 10→	"strings"
 11→	"sync"
 12→	"time"
 13→
 14→	"golang.org/x/time/rate"
 15→)
 16→
 17→// disableRateLimit is evaluated once at startup.
 18→var disableRateLimit = os.Getenv("DISABLE_RATE_LIMIT") == "true"
 19→
 20→// RateLimitTier defines the rate and burst for a category of endpoints.
 21→type RateLimitTier struct {
 22→	Rate  rate.Limit
 23→	Burst int
 24→}
 25→
 26→var tiers = map[string]RateLimitTier{
 27→	"auth":     {Rate: rate.Every(time.Minute / 5), Burst: 5},
 28→	"checkout": {Rate: rate.Every(time.Minute / 10), Burst: 10},
 29→	"geo":      {Rate: rate.Every(time.Minute / 20), Burst: 20},
 30→	"pickup":   {Rate: rate.Every(time.Minute / 5), Burst: 5},
 31→	"webhook":  {Rate: rate.Every(time.Minute / 100), Burst: 100},
 32→	"default":  {Rate: rate.Every(time.Minute / 60), Burst: 60},
 33→}
 34→
 35→type ipLimiter struct {
 36→	limiter  *rate.Limiter
 37→	lastSeen time.Time
 38→}
 39→
 40→type tierLimiters struct {
 41→	mu       sync.Mutex
 42→	limiters map[string]*ipLimiter
 43→	tier     RateLimitTier
 44→}
 45→
 46→func newTierLimiters(ctx context.Context, tier RateLimitTier) *tierLimiters {
 47→	tl := &tierLimiters{
 48→		limiters: make(map[string]*ipLimiter),
 49→		tier:     tier,
 50→	}
 51→	go tl.cleanup(ctx)
 52→	return tl
 53→}
 54→
 55→func (tl *tierLimiters) get(ip string) *rate.Limiter {
 56→	tl.mu.Lock()
 57→	defer tl.mu.Unlock()
 58→
 59→	entry, ok := tl.limiters[ip]
 60→	if !ok {
 61→		entry = &ipLimiter{
 62→			limiter: rate.NewLimiter(tl.tier.Rate, tl.tier.Burst),
 63→		}
 64→		tl.limiters[ip] = entry
 65→	}
 66→	entry.lastSeen = time.Now()
 67→	return entry.limiter
 68→}
 69→
 70→func (tl *tierLimiters) cleanup(ctx context.Context) {
 71→	ticker := time.NewTicker(5 * time.Minute)
 72→	defer ticker.Stop()
 73→	for {
 74→		select {
 75→		case <-ticker.C:
 76→			tl.mu.Lock()
 77→			cutoff := time.Now().Add(-5 * time.Minute)
 78→			for ip, entry := range tl.limiters {
 79→				if entry.lastSeen.Before(cutoff) {
 80→					delete(tl.limiters, ip)
 81→				}
 82→			}
 83→			tl.mu.Unlock()
 84→		case <-ctx.Done():
 85→			return
 86→		}
 87→	}
 88→}
 89→
 90→var (
 91→	tierMu       sync.Mutex
 92→	tierInstances = map[string]*tierLimiters{}
 93→)
 94→
 95→func getTierLimiters(tierName string) *tierLimiters {
 96→	tierMu.Lock()
 97→	defer tierMu.Unlock()
 98→
 99→	tl, ok := tierInstances[tierName]
100→	if !ok {
101→		tier, exists := tiers[tierName]
102→		if !exists {
103→			tier = tiers["default"]
104→		}
105→		tl = newTierLimiters(context.Background(), tier)
106→		tierInstances[tierName] = tl
107→	}
108→	return tl
109→}
110→
111→// WithRateLimit wraps a handler with per-IP rate limiting for the given tier.
112→// Set DISABLE_RATE_LIMIT=true to skip all rate limiting (for E2E / local dev).
113→func WithRateLimit(tier string, next http.HandlerFunc) http.HandlerFunc {
114→	if disableRateLimit {
115→		return next
116→	}
117→
118→	tl := getTierLimiters(tier)
119→
120→	return func(w http.ResponseWriter, r *http.Request) {
121→		ip := clientIP(r)
122→		limiter := tl.get(ip)
123→
124→		if !limiter.Allow() {
125→			w.Header().Set("Content-Type", "application/json")
126→			w.Header().Set("Retry-After", strconv.Itoa(retryAfterSeconds(limiter)))
127→			w.WriteHeader(http.StatusTooManyRequests)
128→			_ = json.NewEncoder(w).Encode(map[string]string{
129→				"error": "rate limit exceeded",
130→			})
131→			return
132→		}
133→
134→		next(w, r)
135→	}
136→}
137→
138→func clientIP(r *http.Request) string {
139→	// Trust X-Forwarded-For when behind a reverse proxy.
140→	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
141→		// Take only the first address if there are multiples.
142→		for j := 0; j < len(xff); j++ {
143→			if xff[j] == ',' {
144→				return strings.TrimSpace(xff[:j])
145→			}
146→		}
147→		return strings.TrimSpace(xff)
148→	}
149→
150→	if ip, _, err := net.SplitHostPort(r.RemoteAddr); err == nil {
151→		return ip
152→	}
153→	return r.RemoteAddr
154→}
155→
156→func retryAfterSeconds(l *rate.Limiter) int {
157→	reservation := l.Reserve()
158→	delay := reservation.Delay()
159→	reservation.Cancel()
160→	seconds := int(delay.Seconds()) + 1
161→	if seconds < 1 {
162→		seconds = 1
163→	}
164→	return seconds
165→}
