 8→
 9→export default function SetupRouter() {
10→  const router = useRouter();
11→  const params = useParams<{ storeId: string }>();
12→  const [error, setError] = useState<string | null>(null);
13→
14→  useEffect(() => {
15→    const token = session.getToken();
16→    if (!token) {
17→      router.replace("/seller/login");
18→      return;
19→    }
20→
21→    const storeId = params.storeId;
22→    let cancelled = false;
23→
24→    async function resolve() {
25→      try {
26→        const [locations, plans] = await Promise.all([
27→          sellerApi.listPickupLocations(token!, storeId),
28→          sellerApi.listSubscriptionPlans(token!, storeId),
29→        ]);
30→
31→        if (cancelled) return;
32→
33→        if (locations.length === 0) {
34→          router.replace(`/seller/stores/${storeId}/setup/location`);
35→          return;
36→        }
37→
38→        if (plans.length === 0) {
39→          router.replace(`/seller/stores/${storeId}/setup/box`);
40→          return;
41→        }
42→
43→        const hasLive = plans.some((p) => p.is_live);
44→        if (hasLive) {
45→          router.replace(`/seller/stores/${storeId}`);
46→          return;
47→        }
48→
49→        // Check Stripe Connect status
50→        const cs = await sellerApi
51→          .connectStatus(token!, storeId)
52→          .catch(() => ({ status: "none" }));
53→
54→        if (cancelled) return;
55→
56→        if (cs.status !== "active") {
57→          router.replace(`/seller/stores/${storeId}/setup/payouts`);
58→          return;
59→        }
60→
61→        router.replace(`/seller/stores/${storeId}/setup/review`);
62→      } catch {
63→        if (!cancelled) setError("Something went wrong. Please try again.");
64→      }
65→    }
66→
67→    resolve();
68→    return () => {
69→      cancelled = true;
70→    };
71→  }, [params.storeId, router]);
72→
73→  if (error) {
74→    return <ErrorAlert error={error} />;
75→  }
76→
77→  return (
78→    <div className="flex items-center justify-center py-12">
79→      <div
80→        className="h-6 w-6 rounded-full border-2 border-[color:var(--lr-leaf)] border-t-transparent animate-spin"
81→        role="status"
82→        aria-label="Loading"
83→      />
84→    </div>
85→  );
86→}
