 29→func (c *Client) FindOrCreateCustomer(ctx context.Context, email string, name *string, phone *string) (string, error) {
 30→	if !c.Enabled() {
 31→		return "", ErrNotConfigured
 32→	}
 33→	// List customers by exact email match (avoids query injection via Search API).
 34→	listParams := &stripe.CustomerListParams{}
 35→	listParams.Context = ctx
 36→	listParams.Filters.AddFilter("email", "", email)
 37→	listParams.Filters.AddFilter("limit", "", "1")
 38→	iter := c.api.Customers.List(listParams)
 39→	if iter.Next() {
 40→		return iter.Customer().ID, nil
 41→	}
 42→	if err := iter.Err(); err != nil {
 43→		return "", err
 44→	}
 45→	// No existing customer found; create one.
 46→	return c.CreateCustomer(ctx, email, name, phone)
 47→}
