 10→	"github.com/jackc/pgx/v5/pgxpool"
 11→
 12→	"github.com/paretoimproved/local-roots/backend/internal/auth"
 13→	"github.com/paretoimproved/local-roots/backend/internal/resp"
 14→)
 15→
 16→type AuthAPI struct {
 17→	DB        *pgxpool.Pool
 18→	JWTSecret string
 19→}
 20→
 21→type AuthUser struct {
 22→	ID          string  `json:"id"`
 23→	Email       string  `json:"email"`
 24→	Role        string  `json:"role"`
 25→	DisplayName *string `json:"display_name"`
 26→}
 27→
 28→type AuthResponse struct {
 29→	Token string   `json:"token"`
 30→	User  AuthUser `json:"user"`
 31→}
 32→
 33→type registerRequest struct {
 34→	Email       string  `json:"email"`
 35→	Password    string  `json:"password"`
 36→	DisplayName *string `json:"display_name"`
 37→	Role        string  `json:"role"` // optional; default "seller"
 38→}
 39→
 40→func (a AuthAPI) Register(w http.ResponseWriter, r *http.Request) {
 41→	if a.DB == nil {
 42→		resp.ServiceUnavailable(w, "database not configured")
 43→		return
 44→	}
 45→	if strings.TrimSpace(a.JWTSecret) == "" {
 46→		resp.ServiceUnavailable(w, "auth not configured")
 47→		return
 48→	}
 49→
 50→	var in registerRequest
 51→	if err := resp.DecodeJSON(w, r, &in); err != nil {
 52→		resp.BadRequest(w, "invalid json")
 53→		return
 54→	}
 55→
 56→	email := strings.ToLower(strings.TrimSpace(in.Email))
 57→	if email == "" || !strings.Contains(email, "@") {
 58→		resp.BadRequest(w, "invalid email")
 59→		return
 60→	}
 61→	if len(in.Password) < 8 {
 62→		resp.BadRequest(w, "password must be at least 8 characters")
 63→		return
 64→	}
 65→
 66→	role := strings.TrimSpace(in.Role)
 67→	if role == "" {
 68→		role = "seller"
 69→	}
 70→	if role != "seller" && role != "buyer" {
 71→		resp.BadRequest(w, "invalid role")
 72→		return
 73→	}
 74→
 75→	hash, err := auth.HashPassword(in.Password)
 76→	if err != nil {
 77→		resp.Internal(w, err)
 78→		return
 79→	}
 80→
 81→	var u AuthUser
 82→	err = a.DB.QueryRow(r.Context(), `
 83→		insert into users (email, role, display_name, password_hash)
 84→		values ($1, $2, $3, $4)
 85→		returning id::text, email, role, display_name
 86→	`, email, role, in.DisplayName, hash).Scan(&u.ID, &u.Email, &u.Role, &u.DisplayName)
 87→	if err != nil {
 88→		// Unique on email.
 89→		if pgxErr, ok := err.(*pgconn.PgError); ok && pgxErr.Code == "23505" {
 90→			resp.BadRequest(w, "email already in use")
 91→			return
 92→		}
 93→		resp.Internal(w, err)
 94→		return
 95→	}
 96→
 97→	var tokenVersion int
 98→	_ = a.DB.QueryRow(r.Context(), `select token_version from users where id = $1::uuid`, u.ID).Scan(&tokenVersion)
 99→
100→	tok, err := auth.SignJWT([]byte(a.JWTSecret), u.ID, u.Role, 4*time.Hour, tokenVersion)
101→	if err != nil {
102→		resp.Internal(w, err)
103→		return
104→	}
105→
106→	resp.OK(w, AuthResponse{Token: tok, User: u})
107→}
108→
109→type loginRequest struct {
110→	Email    string `json:"email"`
111→	Password string `json:"password"`
112→}
113→
114→func (a AuthAPI) Login(w http.ResponseWriter, r *http.Request) {
115→	if a.DB == nil {
116→		resp.ServiceUnavailable(w, "database not configured")
117→		return
118→	}
119→	if strings.TrimSpace(a.JWTSecret) == "" {
120→		resp.ServiceUnavailable(w, "auth not configured")
121→		return
122→	}
123→
124→	var in loginRequest
125→	if err := resp.DecodeJSON(w, r, &in); err != nil {
126→		resp.BadRequest(w, "invalid json")
127→		return
128→	}
129→
130→	email := strings.ToLower(strings.TrimSpace(in.Email))
131→	if email == "" || in.Password == "" {
132→		resp.BadRequest(w, "email and password are required")
133→		return
134→	}
135→
136→	var (
137→		u    AuthUser
138→		hash *string
139→	)
140→	err := a.DB.QueryRow(r.Context(), `
141→		select id::text, email, role, display_name, password_hash
142→		from users
143→		where lower(email) = $1
144→		limit 1
145→	`, email).Scan(&u.ID, &u.Email, &u.Role, &u.DisplayName, &hash)
146→	if err != nil {
147→		if err == pgx.ErrNoRows {
148→			resp.Unauthorized(w, "invalid credentials")
149→			return
150→		}
151→		resp.Internal(w, err)
152→		return
153→	}
154→	if hash == nil {
155→		resp.Unauthorized(w, "invalid credentials")
156→		return
157→	}
158→	if err := auth.CheckPassword(*hash, in.Password); err != nil {
159→		resp.Unauthorized(w, "invalid credentials")
160→		return
161→	}
162→
163→	var tokenVersion int
164→	_ = a.DB.QueryRow(r.Context(), `select token_version from users where id = $1::uuid`, u.ID).Scan(&tokenVersion)
165→
166→	tok, err := auth.SignJWT([]byte(a.JWTSecret), u.ID, u.Role, 4*time.Hour, tokenVersion)
167→	if err != nil {
168→		resp.Internal(w, err)
169→		return
170→	}
171→
172→	resp.OK(w, AuthResponse{Token: tok, User: u})
173→}
174→
175→func (a AuthAPI) RequireUser(next func(http.ResponseWriter, *http.Request, AuthUser)) http.HandlerFunc {
176→	return func(w http.ResponseWriter, r *http.Request) {
177→		if a.DB == nil {
178→			resp.ServiceUnavailable(w, "database not configured")
179→			return
180→		}
181→		if strings.TrimSpace(a.JWTSecret) == "" {
182→			resp.ServiceUnavailable(w, "auth not configured")
183→			return
184→		}
185→
186→		authz := r.Header.Get("Authorization")
187→		parts := strings.SplitN(authz, " ", 2)
188→		if len(parts) != 2 || !strings.EqualFold(parts[0], "bearer") {
189→			resp.Unauthorized(w, "missing bearer token")
190→			return
191→		}
192→
193→		claims, err := auth.ParseJWT([]byte(a.JWTSecret), parts[1])
194→		if err != nil {
195→			resp.Unauthorized(w, "invalid token")
196→			return
197→		}
198→
199→		var u AuthUser
200→		var dbTokenVersion int
201→		err = a.DB.QueryRow(r.Context(), `
202→			select id::text, email, role, display_name, token_version
203→			from users
204→			where id = $1::uuid
205→			limit 1
206→		`, claims.UserID).Scan(&u.ID, &u.Email, &u.Role, &u.DisplayName, &dbTokenVersion)
207→		if err != nil {
208→			if err == pgx.ErrNoRows {
209→				resp.Unauthorized(w, "invalid token")
210→				return
211→			}
212→			resp.Internal(w, err)
213→			return
214→		}
215→
216→		if claims.Version != dbTokenVersion {
217→			resp.Unauthorized(w, "token revoked")
218→			return
219→		}
220→
221→		next(w, r, u)
222→	}
223→}
