  1→package stripepay
  2→
  3→import (
  4→	"context"
  5→	"errors"
  6→	"fmt"
  7→
  8→	stripe "github.com/stripe/stripe-go/v78"
  9→	"github.com/stripe/stripe-go/v78/client"
 10→)
 11→
 12→var ErrNotConfigured = errors.New("stripe not configured")
 13→
 14→type Client struct {
 15→	api *client.API
 16→}
 17→
 18→func New(secretKey string) (*Client, error) {
 19→	if secretKey == "" {
 20→		return nil, ErrNotConfigured
 21→	}
 22→	api := &client.API{}
 23→	api.Init(secretKey, nil)
 24→	return &Client{api: api}, nil
 25→}
 26→
 27→func (c *Client) Enabled() bool { return c != nil && c.api != nil }
 28→
 29→func (c *Client) FindOrCreateCustomer(ctx context.Context, email string, name *string, phone *string) (string, error) {
 30→	if !c.Enabled() {
 31→		return "", ErrNotConfigured
 32→	}
 33→	// List customers by exact email match (avoids query injection via Search API).
 34→	listParams := &stripe.CustomerListParams{}
 35→	listParams.Context = ctx
 36→	listParams.Filters.AddFilter("email", "", email)
 37→	listParams.Filters.AddFilter("limit", "", "1")
 38→	iter := c.api.Customers.List(listParams)
 39→	if iter.Next() {
 40→		return iter.Customer().ID, nil
 41→	}
 42→	if err := iter.Err(); err != nil {
 43→		return "", err
 44→	}
 45→	// No existing customer found; create one.
 46→	return c.CreateCustomer(ctx, email, name, phone)
 47→}
 48→
 49→func (c *Client) CreateCustomer(ctx context.Context, email string, name *string, phone *string) (customerID string, err error) {
 50→	if !c.Enabled() {
 51→		return "", ErrNotConfigured
 52→	}
 53→	p := &stripe.CustomerParams{Email: stripe.String(email)}
 54→	if name != nil && *name != "" {
 55→		p.Name = stripe.String(*name)
 56→	}
 57→	if phone != nil && *phone != "" {
 58→		p.Phone = stripe.String(*phone)
 59→	}
 60→	p.Context = ctx
 61→	cus, err := c.api.Customers.New(p)
 62→	if err != nil {
 63→		return "", err
 64→	}
 65→	return cus.ID, nil
 66→}
 67→
 68→func (c *Client) CreateSetupIntent(ctx context.Context, customerID string, metadata map[string]string) (setupIntentID string, clientSecret string, err error) {
 69→	if !c.Enabled() {
 70→		return "", "", ErrNotConfigured
 71→	}
 72→	if customerID == "" {
 73→		return "", "", fmt.Errorf("missing customer_id")
 74→	}
 75→	p := &stripe.SetupIntentParams{
 76→		Customer: stripe.String(customerID),
 77→		Usage:    stripe.String(string(stripe.SetupIntentUsageOffSession)),
 78→	}
 79→	for k, v := range metadata {
 80→		p.AddMetadata(k, v)
 81→	}
 82→	p.Context = ctx
 83→
 84→	si, err := c.api.SetupIntents.New(p)
 85→	if err != nil {
 86→		return "", "", err
 87→	}
 88→	return si.ID, si.ClientSecret, nil
 89→}
 90→
 91→func (c *Client) RetrieveSetupIntent(ctx context.Context, setupIntentID string) (*stripe.SetupIntent, error) {
 92→	if !c.Enabled() {
 93→		return nil, ErrNotConfigured
 94→	}
 95→	if setupIntentID == "" {
 96→		return nil, fmt.Errorf("missing setup_intent_id")
 97→	}
 98→	p := &stripe.SetupIntentParams{}
 99→	p.Context = ctx
100→	return c.api.SetupIntents.Get(setupIntentID, p)
101→}
