103→type CreateCheckoutPaymentIntentInput struct {
104→	AmountCents int
105→	Currency    string
106→	CustomerID  string
107→	// Metadata values should be stable IDs (plan_id, store_id, etc).
108→	Metadata map[string]string
109→}
110→
111→func (c *Client) CreateCheckoutPaymentIntent(ctx context.Context, in CreateCheckoutPaymentIntentInput) (paymentIntentID string, clientSecret string, err error) {
112→	if !c.Enabled() {
113→		return "", "", ErrNotConfigured
114→	}
115→	if in.AmountCents <= 0 {
116→		return "", "", fmt.Errorf("amount must be > 0")
117→	}
118→	if in.Currency == "" {
119→		in.Currency = "usd"
120→	}
121→	p := &stripe.PaymentIntentParams{
122→		Amount:   stripe.Int64(int64(in.AmountCents)),
123→		Currency: stripe.String(in.Currency),
124→		Customer: stripe.String(in.CustomerID),
125→		// Authorize now, capture later (on pickup confirmation).
126→		CaptureMethod: stripe.String(string(stripe.PaymentIntentCaptureMethodManual)),
127→		// Save the card for future off-session authorizations.
128→		SetupFutureUsage: stripe.String(string(stripe.PaymentIntentSetupFutureUsageOffSession)),
129→	}
130→	for k, v := range in.Metadata {
131→		p.AddMetadata(k, v)
132→	}
133→	p.Context = ctx
134→
135→	pi, err := c.api.PaymentIntents.New(p)
136→	if err != nil {
137→		return "", "", err
138→	}
139→	return pi.ID, pi.ClientSecret, nil
140→}
141→
142→func (c *Client) RetrievePaymentIntent(ctx context.Context, paymentIntentID string) (*stripe.PaymentIntent, error) {
143→	if !c.Enabled() {
144→		return nil, ErrNotConfigured
145→	}
146→	if paymentIntentID == "" {
147→		return nil, fmt.Errorf("missing payment_intent_id")
148→	}
149→	p := &stripe.PaymentIntentParams{}
150→	p.Context = ctx
151→	return c.api.PaymentIntents.Get(paymentIntentID, p)
152→}
153→
154→type CreateOffSessionPaymentIntentInput struct {
155→	AmountCents     int
156→	Currency        string
157→	CustomerID      string
158→	PaymentMethodID string
159→	Metadata        map[string]string
160→	// Used to avoid double-auth when retrying.
161→	IdempotencyKey string
162→}
163→
164→func (c *Client) CreateOffSessionAuthorization(ctx context.Context, in CreateOffSessionPaymentIntentInput) (paymentIntentID string, status string, err error) {
165→	if !c.Enabled() {
166→		return "", "", ErrNotConfigured
167→	}
168→	if in.AmountCents <= 0 {
169→		return "", "", fmt.Errorf("amount must be > 0")
170→	}
171→	if in.CustomerID == "" || in.PaymentMethodID == "" {
172→		return "", "", fmt.Errorf("missing customer/payment method")
173→	}
174→	if in.Currency == "" {
175→		in.Currency = "usd"
176→	}
177→	p := &stripe.PaymentIntentParams{
178→		Amount:        stripe.Int64(int64(in.AmountCents)),
179→		Currency:      stripe.String(in.Currency),
180→		Customer:      stripe.String(in.CustomerID),
181→		PaymentMethod: stripe.String(in.PaymentMethodID),
182→		Confirm:       stripe.Bool(true),
183→		OffSession:    stripe.Bool(true),
184→		CaptureMethod: stripe.String(string(stripe.PaymentIntentCaptureMethodManual)),
185→	}
186→	for k, v := range in.Metadata {
187→		p.AddMetadata(k, v)
188→	}
189→	p.Context = ctx
190→	if in.IdempotencyKey != "" {
191→		p.SetIdempotencyKey(in.IdempotencyKey)
192→	}
193→	pi, err := c.api.PaymentIntents.New(p)
194→	if err != nil {
195→		return "", "", err
196→	}
197→	return pi.ID, string(pi.Status), nil
198→}
199→
200→func (c *Client) CaptureAuthorization(ctx context.Context, paymentIntentID string, idempotencyKey string) error {
201→	if !c.Enabled() {
202→		return ErrNotConfigured
203→	}
204→	p := &stripe.PaymentIntentCaptureParams{}
205→	p.Context = ctx
206→	if idempotencyKey != "" {
207→		p.SetIdempotencyKey(idempotencyKey)
208→	}
209→	_, err := c.api.PaymentIntents.Capture(paymentIntentID, p)
210→	return err
211→}
212→
213→func (c *Client) CaptureAuthorizationAmount(ctx context.Context, paymentIntentID string, amountCents int, idempotencyKey string) error {
214→	if !c.Enabled() {
215→		return ErrNotConfigured
216→	}
217→	if amountCents < 0 {
218→		return fmt.Errorf("amount must be >= 0")
219→	}
220→	p := &stripe.PaymentIntentCaptureParams{}
221→	p.Context = ctx
222→	// Stripe supports partial capture on a manually-captured PaymentIntent. Any remaining
223→	// amount is automatically canceled.
224→	p.AmountToCapture = stripe.Int64(int64(amountCents))
225→	if idempotencyKey != "" {
226→		p.SetIdempotencyKey(idempotencyKey)
227→	}
228→	_, err := c.api.PaymentIntents.Capture(paymentIntentID, p)
229→	return err
230→}
