175→type UpdateOrderStatusRequest struct {
176→	Status   string `json:"status"`
177→	WaiveFee bool   `json:"waive_fee"`
178→}
179→
180→// UpdateOrderStatus supports:
181→// - placed -> ready
182→// - placed -> canceled
183→// - ready  -> no_show
184→func (a SellerOrdersAPI) UpdateOrderStatus(w http.ResponseWriter, r *http.Request, u AuthUser, sc StoreContext) {
185→	orderID := r.PathValue("orderId")
186→	if orderID == "" || !validUUID(orderID) {
187→		resp.BadRequest(w, "missing or invalid orderId")
188→		return
189→	}
190→
191→	var in UpdateOrderStatusRequest
192→	if err := resp.DecodeJSON(w, r, &in); err != nil {
193→		resp.BadRequest(w, "invalid json")
194→		return
195→	}
196→	in.Status = strings.TrimSpace(in.Status)
197→	if in.Status == "" {
198→		resp.BadRequest(w, "status is required")
199→		return
200→	}
201→
202→	ctx := r.Context()
203→	tx, err := a.DB.Begin(ctx)
204→	if err != nil {
205→		resp.Internal(w, err)
206→		return
207→	}
208→	defer tx.Rollback(ctx)
209→
210→	var currentStatus string
211→	var pickupWindowID string
212→	var paymentStatus string
213→	var stripePI *string
214→	var orderDepositCents int
215→	if err := tx.QueryRow(ctx, `
216→		select
217→			status,
218→			pickup_window_id::text,
219→			payment_status,
220→			stripe_payment_intent_id,
221→			deposit_cents
222→		from orders
223→		where id = $1::uuid and store_id = $2::uuid
224→		for update
225→	`, orderID, sc.StoreID).Scan(&currentStatus, &pickupWindowID, &paymentStatus, &stripePI, &orderDepositCents); err != nil {
226→		if err == pgx.ErrNoRows {
227→			resp.NotFound(w, "order not found")
228→			return
229→		}
230→		resp.Internal(w, err)
231→		return
232→	}
233→
234→	if !isAllowedTransition(currentStatus, in.Status) {
235→		resp.BadRequest(w, "invalid status transition")
236→		return
237→	}
238→
239→	newPaymentStatus := paymentStatus
240→	capturedCentsDelta := -1 // -1 means "leave unchanged"
241→
242→	// No-show fee: use order's deposit_cents if set, else config default.
243→	noShowFeeCents := a.NoShowFeeCents
244→	if noShowFeeCents <= 0 {
245→		noShowFeeCents = 500
246→	}
247→	if orderDepositCents > 0 {
248→		noShowFeeCents = orderDepositCents
249→	}
250→
251→	// Track deferred Stripe action to run after commit.
252→	type stripeAction struct {
253→		cancel       bool
254→		captureAmt   int
255→		piID         string
256→		idempotency  string
257→	}
258→	var deferred *stripeAction
259→
260→	trimmedPI := ""
261→	if stripePI != nil {
262→		trimmedPI = strings.TrimSpace(*stripePI)
263→	}
264→
265→	// Adjust inventory reservations/availability based on transition.
266→	if currentStatus == "placed" && in.Status == "canceled" {
267→		if err := adjustOfferingsForOrder(ctx, tx, orderID, "release"); err != nil {
268→			resp.Internal(w, err)
269→			return
270→		}
271→		if a.Stripe == nil || !a.Stripe.Enabled() {
272→			resp.ServiceUnavailable(w, "payments not configured")
273→			return
274→		}
275→		newPaymentStatus = "voided"
276→		deferred = &stripeAction{cancel: true, piID: trimmedPI, idempotency: "void-" + orderID}
277→	}
278→	if currentStatus == "ready" && in.Status == "no_show" {
279→		if err := adjustOfferingsForOrder(ctx, tx, orderID, "release"); err != nil {
280→			resp.Internal(w, err)
281→			return
282→		}
283→		if a.Stripe == nil || !a.Stripe.Enabled() {
284→			resp.ServiceUnavailable(w, "payments not configured")
285→			return
286→		}
287→		if in.WaiveFee || paymentStatus != "authorized" {
288→			newPaymentStatus = "voided"
289→			capturedCentsDelta = 0
290→			deferred = &stripeAction{cancel: true, piID: trimmedPI, idempotency: "void-" + orderID}
291→		} else {
292→			var totalCents int
293→			if err := tx.QueryRow(ctx, `select total_cents from orders where id = $1::uuid`, orderID).Scan(&totalCents); err != nil {
294→				resp.Internal(w, err)
295→				return
296→			}
297→			fee := noShowFeeCents
298→			if totalCents < fee {
299→				fee = totalCents
300→			}
301→			if fee <= 0 {
302→				newPaymentStatus = "voided"
303→				capturedCentsDelta = 0
304→				deferred = &stripeAction{cancel: true, piID: trimmedPI, idempotency: "void-" + orderID}
305→			} else {
306→				newPaymentStatus = "paid"
307→				capturedCentsDelta = fee
308→				deferred = &stripeAction{captureAmt: fee, piID: trimmedPI, idempotency: "noshow-" + orderID}
309→			}
310→		}
311→	}
312→	// Note: ready -> picked_up is intentionally handled via ConfirmPickup (pickup-code handshake),
313→	// not via this generic status endpoint.
314→
315→	if capturedCentsDelta >= 0 {
316→		if _, err := tx.Exec(ctx, `
317→			update orders
318→			set status = $2,
319→				payment_status = $3,
320→				captured_cents = $4,
321→				updated_at = now()
322→			where id = $1::uuid
323→		`, orderID, in.Status, newPaymentStatus, capturedCentsDelta); err != nil {
324→			resp.Internal(w, err)
325→			return
326→		}
327→	} else {
328→		if _, err := tx.Exec(ctx, `
329→			update orders
330→			set status = $2, payment_status = $3, updated_at = now()
331→			where id = $1::uuid
332→		`, orderID, in.Status, newPaymentStatus); err != nil {
333→			resp.Internal(w, err)
334→			return
335→		}
336→	}
337→
338→	if err := tx.Commit(ctx); err != nil {
339→		resp.Internal(w, err)
340→		return
341→	}
342→
343→	// Call Stripe after commit. If this fails, the webhook will reconcile.
344→	if deferred != nil {
345→		if deferred.cancel {
346→			_ = a.Stripe.CancelPaymentIntent(ctx, deferred.piID, deferred.idempotency)
347→		} else {
348→			_ = a.Stripe.CaptureAuthorizationAmount(ctx, deferred.piID, deferred.captureAmt, deferred.idempotency)
349→

349→
350→			// No-show fee split: transfer seller's share to their Connect account.
351→			if in.Status == "no_show" && deferred.captureAmt > 0 {
352→				splitBps := a.NoShowPlatformSplitBps
353→				if splitBps <= 0 {
354→					splitBps = 3000 // 30% platform default
355→				}
356→				platformShare := (deferred.captureAmt * splitBps) / 10000
357→				sellerShare := deferred.captureAmt - platformShare
358→				transferToSeller(ctx, a.DB, a.Stripe, sc.StoreID, orderID, deferred.piID, sellerShare, "noshow-transfer-")
359→			}
360→		}
361→	}
362→
363→	// Send status-change emails (fire-and-forget).
364→	if a.Email != nil && a.Email.Enabled() && a.FrontendURL != "" {
365→		if info, ok := fetchOrderEmailInfo(ctx, a.DB, orderID); ok {
366→			orderURL := strings.TrimRight(a.FrontendURL, "/") + "/orders/" + orderID + "?t=" + info.buyerToken
367→
368→			switch in.Status {
369→			case "ready":
370→				subj, body := email.OrderReady(info.boxTitle, info.pickupCode, orderURL)
371→				a.Email.SendAsync(info.buyerEmail, subj, body)
372→			case "canceled":
373→				subj, body := email.OrderCanceled(info.boxTitle, orderURL)
374→				a.Email.SendAsync(info.buyerEmail, subj, body)
375→			case "no_show":
376→				if in.WaiveFee || capturedCentsDelta <= 0 {
377→					subj, body := email.NoShowWaived(info.boxTitle, orderURL)
378→					a.Email.SendAsync(info.buyerEmail, subj, body)
379→				} else {
380→					feeStr := fmt.Sprintf("$%.2f", float64(capturedCentsDelta)/100.0)
381→					subj, body := email.NoShowNotification(info.boxTitle, feeStr, orderURL)
382→					a.Email.SendAsync(info.buyerEmail, subj, body)
383→				}
384→			}
385→		}
386→	}
387→
388→	resp.OK(w, map[string]any{
389→		"id":               orderID,
390→		"store_id":         sc.StoreID,
391→		"pickup_window_id": pickupWindowID,
392→		"status":           in.Status,
393→	})
394→}
