 4→	"log"
 5→	"net/http"
 6→	"time"
 7→)
 8→
 9→type statusWriter struct {
10→	http.ResponseWriter
11→	status int
12→	bytes  int
13→}
14→
15→func (w *statusWriter) WriteHeader(code int) {
16→	w.status = code
17→	w.ResponseWriter.WriteHeader(code)
18→}
19→
20→func (w *statusWriter) Write(p []byte) (int, error) {
21→	if w.status == 0 {
22→		w.status = http.StatusOK
23→	}
24→	n, err := w.ResponseWriter.Write(p)
25→	w.bytes += n
26→	return n, err
27→}
28→
29→func withLogging(next http.Handler) http.Handler {
30→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
31→		// Keep noise low.
32→		if r.URL.Path == "/health" {
33→			next.ServeHTTP(w, r)
34→			return
35→		}
36→
37→		start := time.Now()
38→		sw := &statusWriter{ResponseWriter: w}
39→		next.ServeHTTP(sw, r)
40→		dur := time.Since(start)
41→
42→		// Railway adds this header when present; useful for correlating edge logs.
43→		reqID := r.Header.Get("X-Railway-Request-Id")
44→		if reqID == "" {
45→			reqID = r.Header.Get("X-Request-Id")
46→		}
47→
48→		if reqID != "" {
49→			log.Printf("%s %s -> %d (%dB) %s rid=%s", r.Method, r.URL.Path, sw.status, sw.bytes, dur, reqID)
50→		} else {
51→			log.Printf("%s %s -> %d (%dB) %s", r.Method, r.URL.Path, sw.status, sw.bytes, dur)
52→		}
53→	})
54→}
