 1→const TOKEN_KEY = "localroots_token";
 2→const LEGACY_BUYER_TOKEN_KEY = "localroots_buyer_token";
 3→
 4→const listeners = new Set<() => void>();
 5→function notify() { listeners.forEach((fn) => fn()); }
 6→
 7→export function subscribe(fn: () => void) {
 8→  listeners.add(fn);
 9→  return () => { listeners.delete(fn); };
10→}
11→
12→if (typeof window !== "undefined") {
13→  window.addEventListener("storage", (e) => {
14→    if (e.key === TOKEN_KEY || e.key === LEGACY_BUYER_TOKEN_KEY) {
15→      notify();
16→    }
17→  });
18→}
19→
20→export const session = {
21→  getToken(): string | null {
22→    if (typeof window === "undefined") return null;
23→    return window.localStorage.getItem(TOKEN_KEY);
24→  },
25→  setToken(token: string) {
26→    if (typeof window === "undefined") return;
27→    window.localStorage.setItem(TOKEN_KEY, token);
28→    // Remove legacy buyer key so there's only one source of truth.
29→    window.localStorage.removeItem(LEGACY_BUYER_TOKEN_KEY);
30→    notify();
31→  },
32→  clearToken() {
33→    if (typeof window === "undefined") return;
34→    window.localStorage.removeItem(TOKEN_KEY);
35→    window.localStorage.removeItem(LEGACY_BUYER_TOKEN_KEY);
36→    notify();
37→  },
38→};
