  8→func TestAddCadence(t *testing.T) {
  9→	loc := time.UTC
 10→
 11→	t.Run("weekly adds 7 days", func(t *testing.T) {
 12→		start := time.Date(2026, 2, 14, 10, 0, 0, 0, time.UTC)
 13→		got := addCadence(start, "weekly", loc)
 14→		want := time.Date(2026, 2, 21, 10, 0, 0, 0, time.UTC)
 15→		if !got.Equal(want) {
 16→			t.Fatalf("got %s want %s", got.Format(time.RFC3339), want.Format(time.RFC3339))
 17→		}
 18→	})
 19→
 20→	t.Run("biweekly adds 14 days", func(t *testing.T) {
 21→		start := time.Date(2026, 2, 1, 12, 0, 0, 0, time.UTC)
 22→		got := addCadence(start, "biweekly", loc)
 23→		want := time.Date(2026, 2, 15, 12, 0, 0, 0, time.UTC)
 24→		if !got.Equal(want) {
 25→			t.Fatalf("got %s want %s", got.Format(time.RFC3339), want.Format(time.RFC3339))
 26→		}
 27→	})
 28→
 29→	t.Run("monthly adds 1 month", func(t *testing.T) {
 30→		start := time.Date(2026, 1, 15, 10, 0, 0, 0, time.UTC)
 31→		got := addCadence(start, "monthly", loc)
 32→		want := time.Date(2026, 2, 15, 10, 0, 0, 0, time.UTC)
 33→		if !got.Equal(want) {
 34→			t.Fatalf("got %s want %s", got.Format(time.RFC3339), want.Format(time.RFC3339))
 35→		}
 36→	})
 37→
 38→	t.Run("monthly end-of-month overflow", func(t *testing.T) {
 39→		start := time.Date(2026, 1, 31, 10, 0, 0, 0, time.UTC)
 40→		got := addCadence(start, "monthly", loc)
 41→		// Go's AddDate: Jan 31 + 1 month = March 3 (2026 is not a leap year)
 42→		want := time.Date(2026, 3, 3, 10, 0, 0, 0, time.UTC)
 43→		if !got.Equal(want) {
 44→			t.Fatalf("got %s want %s", got.Format(time.RFC3339), want.Format(time.RFC3339))
 45→		}
 46→	})
 47→
 48→	t.Run("unknown cadence defaults to weekly", func(t *testing.T) {
 49→		start := time.Date(2026, 2, 14, 10, 0, 0, 0, time.UTC)
 50→		got := addCadence(start, "daily", loc)
 51→		want := time.Date(2026, 2, 21, 10, 0, 0, 0, time.UTC)
 52→		if !got.Equal(want) {
 53→			t.Fatalf("got %s want %s", got.Format(time.RFC3339), want.Format(time.RFC3339))
 54→		}
 55→	})
 56→
 57→	t.Run("DST spring forward", func(t *testing.T) {
 58→		chi, err := time.LoadLocation("America/Chicago")
 59→		if err != nil {
 60→			t.Skip("America/Chicago timezone not available")
 61→		}
 62→		// March 8 2026 is DST spring-forward in US Central
 63→		start := time.Date(2026, 3, 7, 10, 0, 0, 0, chi).UTC()
 64→		got := addCadence(start, "weekly", chi)
 65→		// Should keep wall-clock time 10:00 local, even though UTC offset changes
 66→		gotLocal := got.In(chi)
 67→		if gotLocal.Hour() != 10 || gotLocal.Minute() != 0 {
 68→			t.Fatalf("expected 10:00 local, got %s", gotLocal.Format(time.RFC3339))
 69→		}
 70→		if gotLocal.Day() != 14 {
 71→			t.Fatalf("expected day 14, got %d", gotLocal.Day())
 72→		}
 73→	})
 74→
 75→	t.Run("DST fall back", func(t *testing.T) {
 76→		chi, err := time.LoadLocation("America/Chicago")
 77→		if err != nil {
 78→			t.Skip("America/Chicago timezone not available")
 79→		}
 80→		// Nov 1 2026 is DST fall-back in US Central
 81→		start := time.Date(2026, 10, 31, 10, 0, 0, 0, chi).UTC()
 82→		got := addCadence(start, "weekly", chi)
 83→		gotLocal := got.In(chi)
 84→		if gotLocal.Hour() != 10 || gotLocal.Minute() != 0 {
 85→			t.Fatalf("expected 10:00 local, got %s", gotLocal.Format(time.RFC3339))
 86→		}
 87→		if gotLocal.Day() != 7 {
 88→			t.Fatalf("expected day 7, got %d", gotLocal.Day())
 89→		}
 90→	})
