  5→// TestNoShowFeeSplit verifies the platform/seller split math used in
  6→// UpdateOrderStatus and seller_payouts.
  7→func TestNoShowFeeSplit(t *testing.T) {
  8→	cases := []struct {
  9→		name           string
 10→		capturedCents  int
 11→		splitBps       int
 12→		wantPlatform   int
 13→		wantSeller     int
 14→	}{
 15→		{
 16→			name:          "default 30/70 on $5.00",
 17→			capturedCents: 500, splitBps: 3000,
 18→			wantPlatform: 150, wantSeller: 350,
 19→		},
 20→		{
 21→			name:          "50/50 split on $10.00",
 22→			capturedCents: 1000, splitBps: 5000,
 23→			wantPlatform: 500, wantSeller: 500,
 24→		},
 25→		{
 26→			name:          "0% platform (all to seller)",
 27→			capturedCents: 500, splitBps: 0,
 28→			wantPlatform: 0, wantSeller: 500,
 29→		},
 30→		{
 31→			name:          "100% platform (nothing to seller)",
 32→			capturedCents: 500, splitBps: 10000,
 33→			wantPlatform: 500, wantSeller: 0,
 34→		},
 35→		{
 36→			name:          "rounding truncates toward platform",
 37→			capturedCents: 333, splitBps: 3000,
 38→			// 333 * 3000 / 10000 = 99.9 → truncates to 99
 39→			wantPlatform: 99, wantSeller: 234,
 40→		},
 41→		{
 42→			name:          "zero captured",
 43→			capturedCents: 0, splitBps: 3000,
 44→			wantPlatform: 0, wantSeller: 0,
 45→		},
 46→		{
 47→			name:          "small amount $0.01",
 48→			capturedCents: 1, splitBps: 3000,
 49→			// 1 * 3000 / 10000 = 0 (truncated)
 50→			wantPlatform: 0, wantSeller: 1,
 51→		},
 52→	}
 53→
 54→	for _, tc := range cases {
 55→		t.Run(tc.name, func(t *testing.T) {
 56→			platformShare := (tc.capturedCents * tc.splitBps) / 10000
 57→			sellerShare := tc.capturedCents - platformShare
 58→
 59→			if platformShare != tc.wantPlatform {
 60→				t.Errorf("platform: got %d want %d", platformShare, tc.wantPlatform)
 61→			}
 62→			if sellerShare != tc.wantSeller {
 63→				t.Errorf("seller: got %d want %d", sellerShare, tc.wantSeller)
 64→			}
 65→			// Invariant: platform + seller = captured
 66→			if platformShare+sellerShare != tc.capturedCents {
 67→				t.Errorf("split doesn't sum: %d + %d != %d", platformShare, sellerShare, tc.capturedCents)
 68→			}
 69→		})
 70→	}
 71→}
