  9→// TestConnectAccountStatusDerivation verifies the status derivation logic
 10→// used in both GetAccountStatus and the account.updated webhook handler.
 11→// This logic MUST be identical in both places.
 12→func TestConnectAccountStatusDerivation(t *testing.T) {
 13→	cases := []struct {
 14→		name           string
 15→		chargesEnabled bool
 16→		payoutsEnabled bool
 17→		hasErrors      bool
 18→		wantStatus     string
 19→	}{
 20→		{
 21→			name:           "both enabled = active",
 22→			chargesEnabled: true, payoutsEnabled: true,
 23→			wantStatus: "active",
 24→		},
 25→		{
 26→			name:           "neither enabled = onboarding",
 27→			chargesEnabled: false, payoutsEnabled: false,
 28→			wantStatus: "onboarding",
 29→		},
 30→		{
 31→			name:           "only charges = restricted",
 32→			chargesEnabled: true, payoutsEnabled: false,
 33→			wantStatus: "restricted",
 34→		},
 35→		{
 36→			name:           "only payouts = restricted",
 37→			chargesEnabled: false, payoutsEnabled: true,
 38→			wantStatus: "restricted",
 39→		},
 40→		{
 41→			name:           "neither with errors = restricted",
 42→			chargesEnabled: false, payoutsEnabled: false,
 43→			hasErrors:  true,
 44→			wantStatus: "restricted",
 45→		},
 46→		{
 47→			name:           "both enabled with errors = active (errors don't downgrade active)",
 48→			chargesEnabled: true, payoutsEnabled: true,
 49→			hasErrors:  true,
 50→			wantStatus: "active",
 51→		},
 52→	}
 53→
 54→	for _, tc := range cases {
 55→		t.Run(tc.name, func(t *testing.T) {
 56→			// Derive status using the same logic as GetAccountStatus and webhook
 57→			status := deriveConnectStatus(tc.chargesEnabled, tc.payoutsEnabled, tc.hasErrors)
 58→			if status != tc.wantStatus {
 59→				t.Errorf("got %q want %q", status, tc.wantStatus)
 60→			}
 61→		})
 62→	}
 63→}
 64→
 65→// deriveConnectStatus extracts the common status derivation logic.
 66→// This should match the logic in:
 67→// - stripepay.GetAccountStatus
 68→// - stripe_webhook.go account.updated handler
 69→func deriveConnectStatus(chargesEnabled, payoutsEnabled, hasErrors bool) string {
 70→	if chargesEnabled && payoutsEnabled {
 71→		return "active"
 72→	}
 73→	if hasErrors {
 74→		return "restricted"
 75→	}
 76→	if chargesEnabled || payoutsEnabled {
 77→		return "restricted"
 78→	}
 79→	return "onboarding"
 80→}
 81→
 82→// TestGetAccountStatusMatchesDerivation verifies that GetAccountStatus uses
 83→// the same derivation as our extracted function, by constructing equivalent
 84→// stripe.Account objects.
 85→func TestGetAccountStatusMatchesDerivation(t *testing.T) {
 86→	scenarios := []struct {
 87→		chargesEnabled bool
 88→		payoutsEnabled bool
 89→		errors         []*stripe.AccountRequirementsError
 90→	}{
 91→		{true, true, nil},
 92→		{false, false, nil},
 93→		{true, false, nil},
 94→		{false, true, nil},
 95→		{false, false, []*stripe.AccountRequirementsError{{Code: "some_error"}}},
 96→		{true, true, []*stripe.AccountRequirementsError{{Code: "some_error"}}},
 97→	}
 98→
 99→	for _, s := range scenarios {
100→		// Simulate what GetAccountStatus does internally
101→		acctStatus := "onboarding"
102→		if s.chargesEnabled && s.payoutsEnabled {
103→			acctStatus = "active"
104→		} else if len(s.errors) > 0 {
105→			acctStatus = "restricted"
106→		} else if s.chargesEnabled || s.payoutsEnabled {
107→			acctStatus = "restricted"
108→		}
109→
110→		expected := deriveConnectStatus(s.chargesEnabled, s.payoutsEnabled, len(s.errors) > 0)
111→		if acctStatus != expected {
112→			t.Errorf("charges=%v payouts=%v errors=%d: GetAccountStatus logic gives %q but deriveConnectStatus gives %q",
113→				s.chargesEnabled, s.payoutsEnabled, len(s.errors), acctStatus, expected)
114→		}
115→	}
116→}
