  5→// TestBuyerFeeConsistency verifies that the fee calculation used in:
  6→// 1. Subscription checkout (SubscriptionAPI.Checkout)
  7→// 2. Subscription subscribe PI validation (SubscriptionAPI.Subscribe)
  8→// 3. Order checkout (OrderCheckoutAPI.Checkout)
  9→// 4. Order creation (OrdersAPI.CreateOrder)
 10→// 5. Cycle generation (SellerSubscriptionAPI.GenerateNextCycle)
 11→//
 12→// ALL use the same computeBuyerFee formula. This prevents the bug where
 13→// checkout creates a PI for totalCents but subscribe validates against priceCents.
 14→func TestBuyerFeeConsistency(t *testing.T) {
 15→	cases := []struct {
 16→		name     string
 17→		subtotal int
 18→		bps      int
 19→		flat     int
 20→	}{
 21→		{"zero fees", 2000, 0, 0},
 22→		{"bps only", 2000, 500, 0},
 23→		{"flat only", 2000, 0, 50},
 24→		{"combined", 2000, 250, 50},
 25→		{"large amount", 50000, 500, 100},
 26→		{"small amount", 100, 500, 0},
 27→	}
 28→
 29→	for _, tc := range cases {
 30→		t.Run(tc.name, func(t *testing.T) {
 31→			fee, total := computeBuyerFee(tc.subtotal, tc.bps, tc.flat)
 32→
 33→			// Basic math invariant
 34→			if total != tc.subtotal+fee {
 35→				t.Errorf("total (%d) != subtotal (%d) + fee (%d)", total, tc.subtotal, fee)
 36→			}
 37→
 38→			// The inline fee calculation used in OrderCheckoutAPI.Checkout and
 39→			// OrdersAPI.CreateOrder must produce the same result.
 40→			inlineFee := (tc.subtotal * tc.bps) / 10000
 41→			if tc.flat > 0 {
 42→				inlineFee += tc.flat
 43→			}
 44→			inlineTotal := tc.subtotal + inlineFee
 45→
 46→			if inlineFee != fee {
 47→				t.Errorf("inline fee (%d) != computeBuyerFee fee (%d)", inlineFee, fee)
 48→			}
 49→			if inlineTotal != total {
 50→				t.Errorf("inline total (%d) != computeBuyerFee total (%d)", inlineTotal, total)
 51→			}
 52→		})
 53→	}
 54→}
