 56→// TestSubscribePIValidationMatchesCheckout verifies that the PI amount validation
 57→// in Subscribe uses totalCents (not priceCents), matching what Checkout creates.
 58→//
 59→// This was a real bug: Checkout creates PI for totalCents, but Subscribe compared
 60→// against priceCents. When buyer fees > 0, subscriptions would fail.
 61→func TestSubscribePIValidationMatchesCheckout(t *testing.T) {
 62→	cases := []struct {
 63→		name       string
 64→		priceCents int
 65→		bps        int
 66→		flat       int
 67→	}{
 68→		{"no fees", 2500, 0, 0},
 69→		{"5% fee", 2500, 500, 0},
 70→		{"flat $0.50 fee", 2500, 0, 50},
 71→		{"combined 2.5% + $0.50", 2500, 250, 50},
 72→	}
 73→
 74→	for _, tc := range cases {
 75→		t.Run(tc.name, func(t *testing.T) {
 76→			// Checkout creates PI with this amount:
 77→			_, checkoutTotal := computeBuyerFee(tc.priceCents, tc.bps, tc.flat)
 78→
 79→			// Subscribe validates PI.Amount against this (the fixed version):
 80→			_, expectedTotal := computeBuyerFee(tc.priceCents, tc.bps, tc.flat)
 81→
 82→			if checkoutTotal != expectedTotal {
 83→				t.Errorf("checkout total (%d) != subscribe validation total (%d)", checkoutTotal, expectedTotal)
 84→			}
 85→
 86→			// Would have failed before the fix (comparing against priceCents):
 87→			if tc.bps > 0 || tc.flat > 0 {
 88→				if checkoutTotal == tc.priceCents {
 89→					t.Error("with fees > 0, checkout total should differ from priceCents")
 90→				}
 91→			}
 92→		})
 93→	}
 94→}
