 96→// TestPayoutSummaryAccuracy verifies the payout math for seller payouts.
 97→func TestPayoutSummaryAccuracy(t *testing.T) {
 98→	cases := []struct {
 99→		name               string
100→		pickedUpSubtotals  []int // subtotal_cents per picked_up order
101→		pickedUpFees       []int // buyer_fee_cents per picked_up order
102→		noShowCaptures     []int // captured_cents per no_show order
103→		noShowSplitBps     int
104→		wantSellerPayout   int
105→		wantPlatformFee    int
106→	}{
107→		{
108→			name:              "simple pickup, no no-shows",
109→			pickedUpSubtotals: []int{2000, 3000},
110→			pickedUpFees:      []int{100, 150},
111→			noShowSplitBps:    3000,
112→			wantSellerPayout:  5000,   // sum of subtotals
113→			wantPlatformFee:   250,    // sum of buyer fees
114→		},
115→		{
116→			name:              "no-show with 30/70 split",
117→			noShowCaptures:    []int{500},
118→			noShowSplitBps:    3000,
119→			wantSellerPayout:  350,    // 500 - 150
120→			wantPlatformFee:   150,    // 500 * 0.30
121→		},
122→		{
123→			name:              "mixed pickup and no-show",
124→			pickedUpSubtotals: []int{2000},
125→			pickedUpFees:      []int{100},
126→			noShowCaptures:    []int{500},
127→			noShowSplitBps:    3000,
128→			wantSellerPayout:  2350,   // 2000 + 350
129→			wantPlatformFee:   250,    // 100 + 150
130→		},
131→		{
132→			name:              "no orders",
133→			noShowSplitBps:    3000,
134→			wantSellerPayout:  0,
135→			wantPlatformFee:   0,
136→		},
137→	}
138→
139→	for _, tc := range cases {
140→		t.Run(tc.name, func(t *testing.T) {
141→			// Compute picked-up payout (subtotals go to seller, fees to platform)
142→			payoutPickedUp := 0
143→			platformFees := 0
144→			for i, sub := range tc.pickedUpSubtotals {
145→				payoutPickedUp += sub
146→				platformFees += tc.pickedUpFees[i]
147→			}
148→
149→			// Compute no-show payout with split
150→			grossNoShow := 0
151→			for _, cap := range tc.noShowCaptures {
152→				grossNoShow += cap
153→			}
154→			splitBps := tc.noShowSplitBps
155→			if splitBps <= 0 {
156→				splitBps = 3000
157→			}
158→			platformNoShow := (grossNoShow * splitBps) / 10000
159→			payoutNoShow := grossNoShow - platformNoShow
160→			platformFees += platformNoShow
161→
162→			sellerPayout := payoutPickedUp + payoutNoShow
163→
164→			if sellerPayout != tc.wantSellerPayout {
165→				t.Errorf("sellerPayout: got %d want %d", sellerPayout, tc.wantSellerPayout)
166→			}
167→			if platformFees != tc.wantPlatformFee {
168→				t.Errorf("platformFees: got %d want %d", platformFees, tc.wantPlatformFee)
169→			}
170→		})
171→	}
172→}
