 5→// TestOrderLifecycle verifies the complete order state machine including
 6→// transitions via both UpdateOrderStatus and ConfirmPickup.
 7→//
 8→// Valid lifecycle paths:
 9→//   placed → ready → picked_up (via ConfirmPickup with pickup code)
10→//   placed → picked_up (via ConfirmPickup — walkup farmstand scan)
11→//   placed → ready → no_show (via UpdateOrderStatus)
12→//   placed → canceled (via UpdateOrderStatus)
13→//
14→// Invalid:
15→//   placed → picked_up via UpdateOrderStatus (must use ConfirmPickup)
16→//   ready → canceled (can only cancel from placed)
17→//   any terminal state → anything
18→func TestOrderLifecycle(t *testing.T) {
19→	// Test all valid paths through the state machine.
20→	validPaths := []struct {
21→		name  string
22→		steps []string
23→	}{
24→		{"happy path: placed→ready→picked_up", []string{"placed", "ready", "picked_up"}},
25→		{"walkup scan: placed→picked_up", []string{"placed", "picked_up"}},
26→		{"no-show: placed→ready→no_show", []string{"placed", "ready", "no_show"}},
27→		{"early cancel: placed→canceled", []string{"placed", "canceled"}},
28→	}
29→
30→	for _, tc := range validPaths {
31→		t.Run(tc.name, func(t *testing.T) {
32→			for i := 0; i < len(tc.steps)-1; i++ {
33→				from, to := tc.steps[i], tc.steps[i+1]
34→				// picked_up is only via ConfirmPickup, not isAllowedTransition
35→				if to == "picked_up" {
36→					// ConfirmPickup accepts from="placed" or from="ready"
37→					if from != "placed" && from != "ready" {
38→						t.Errorf("ConfirmPickup requires from=placed or from=ready, got %q", from)
39→					}
40→					continue
41→				}
42→				if !isAllowedTransition(from, to) {
43→					t.Errorf("transition %q→%q should be allowed", from, to)
44→				}
45→			}
46→		})
47→	}
48→
49→	// Test that direct placed→picked_up via UpdateOrderStatus is blocked
50→	// (must use ConfirmPickup with pickup code).

