  font-family: var(--font-lr-sans), ui-sans-serif, system-ui, -apple-system,
    "Segoe UI", sans-serif;
}

h1,
h2,
h3 {
  font-family: var(--font-lr-serif), ui-serif, Georgia, serif;
}

