  1→"use client";
  2→
  3→import { Suspense, useEffect, useState, useCallback, useRef } from "react";
  4→import Link from "next/link";
  5→import { useSearchParams } from "next/navigation";
  6→import { api, type Store, type PlacePrediction } from "@/lib/api";
  7→import { requestJSON } from "@/lib/http";
  8→import { session } from "@/lib/session";
  9→import { StoreCard } from "@/components/store-card";
 10→
 11→const RADIUS_OPTIONS = [
 12→  { label: "10 mi", km: 16 },
 13→  { label: "25 mi", km: 40 },
 14→  { label: "50 mi", km: 80 },
 15→  { label: "100 mi", km: 161 },
 16→] as const;
 17→
 18→const DEFAULT_RADIUS_KM = 40;
 19→
 20→export default function StoresPage() {
 21→  return (
 22→    <Suspense>
 23→      <StoresContent />
 24→    </Suspense>
 25→  );
 26→}
 27→
 28→function StoresContent() {
 29→  const searchParams = useSearchParams();
 30→  const isDemo = searchParams.get("demo") === "true";
 31→
 32→  const [stores, setStores] = useState<Store[] | null>(null);
 33→  const [error, setError] = useState<string | null>(null);
 34→  const [loading, setLoading] = useState(true);
 35→  const [hasLocation, setHasLocation] = useState(false);
 36→  const [coords, setCoords] = useState<{ lat: number; lng: number } | null>(
 37→    null,
 38→  );
 39→  const [radiusKm, setRadiusKm] = useState(DEFAULT_RADIUS_KM);
 40→  const [locationLabel, setLocationLabel] = useState<string | null>(null);
 41→  const [searchQuery, setSearchQuery] = useState("");
 42→  const [searchError, setSearchError] = useState<string | null>(null);
 43→  const [notifyEmail, setNotifyEmail] = useState("");
 44→  const [notifySubmitted, setNotifySubmitted] = useState(false);
 45→
 46→  // Autocomplete state
 47→  const [predictions, setPredictions] = useState<PlacePrediction[]>([]);
 48→  const [showDropdown, setShowDropdown] = useState(false);
 49→  const [activeIndex, setActiveIndex] = useState(-1);
 50→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 51→  const wrapperRef = useRef<HTMLDivElement>(null);
 52→
 53→  const fetchStores = useCallback(
 54→    async (loc?: { lat: number; lng: number } | null, radius?: number) => {
 55→      setLoading(true);
 56→      setError(null);
 57→      try {
 58→        const token = isDemo ? session.getToken() ?? undefined : undefined;
 59→        const opts = loc
 60→          ? { lat: loc.lat, lng: loc.lng, radius_km: radius ?? radiusKm, demo: isDemo || undefined, token }
 61→          : isDemo ? { demo: true, token } : undefined;
 62→        const data = await api.listStores(opts);
 63→        setStores(data);
 64→        setHasLocation(!!loc);
 65→      } catch (e) {
 66→        setError(e instanceof Error ? e.message : "Unknown error");
 67→      } finally {
 68→        setLoading(false);
 69→      }
 70→    },
 71→    [radiusKm, isDemo],
 72→  );
 73→
 74→  // Initial load: show all stores; detect geolocation silently for search
 75→  useEffect(() => {
 76→    fetchStores();
 77→
 78→    if (navigator.geolocation) {
 79→      navigator.geolocation.getCurrentPosition(
 80→        (pos) => {
 81→          setCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude });
 82→        },
 83→        () => {},
 84→        { timeout: 5000 },
 85→      );
 86→    }
 87→    // eslint-disable-next-line react-hooks/exhaustive-deps
 88→  }, []);
 89→
 90→  // Re-fetch when radius changes (only if we have coords)
 91→  useEffect(() => {
 92→    if (coords) {
 93→      fetchStores(coords, radiusKm);
 94→    }
 95→    // eslint-disable-next-line react-hooks/exhaustive-deps
 96→  }, [radiusKm]);
 97→
 98→  // Close dropdown on outside click
 99→  useEffect(() => {
100→    function handleClick(e: MouseEvent) {
101→      if (
102→        wrapperRef.current &&
103→        !wrapperRef.current.contains(e.target as Node)
104→      ) {
105→        setShowDropdown(false);
106→      }
107→    }
108→    document.addEventListener("mousedown", handleClick);
109→    return () => document.removeEventListener("mousedown", handleClick);
110→  }, []);
111→
112→  // Debounced autocomplete
113→  function handleInputChange(value: string) {
114→    setSearchQuery(value);
115→    setSearchError(null);
116→    setActiveIndex(-1);
117→
118→    if (debounceRef.current) clearTimeout(debounceRef.current);
119→
120→    if (value.trim().length < 2) {
121→      setPredictions([]);
122→      setShowDropdown(false);
123→      return;
124→    }
125→
126→    debounceRef.current = setTimeout(async () => {
127→      try {
128→        const results = await api.placesAutocomplete(value.trim());
129→        setPredictions(results);
130→        setShowDropdown(results.length > 0);
131→      } catch {
132→        setPredictions([]);
133→        setShowDropdown(false);
134→      }
135→    }, 250);
136→  }
137→
138→  async function selectPrediction(prediction: PlacePrediction) {
139→    setSearchQuery(prediction.label);
140→    setShowDropdown(false);
141→    setPredictions([]);
142→    setSearchError(null);
143→
144→    try {
145→      const result = await api.geocode({ place_id: prediction.place_id });
146→      const loc = { lat: result.lat, lng: result.lng };
147→      setCoords(loc);
148→      setLocationLabel(result.label);
149→      await fetchStores(loc);
150→    } catch {
151→      setSearchError("Could not find that location. Try a different search.");
152→    }
153→  }
154→
155→  async function handleSubmit(e: React.FormEvent) {
156→    e.preventDefault();
157→    const q = searchQuery.trim();
158→    if (q.length < 2) return;
159→
160→    setShowDropdown(false);
161→    setPredictions([]);
162→    setSearchError(null);
163→
164→    try {
165→      const result = await api.geocode({ q });
166→      const loc = { lat: result.lat, lng: result.lng };
167→      setCoords(loc);
168→      setLocationLabel(result.label);
169→      await fetchStores(loc);
170→    } catch {
171→      setSearchError("Could not find that location. Try a city or zip code.");
172→    }
173→  }
174→
175→  function handleKeyDown(e: React.KeyboardEvent) {
176→    if (!showDropdown || predictions.length === 0) return;
177→
178→    if (e.key === "ArrowDown") {
179→      e.preventDefault();
180→      setActiveIndex((prev) =>
181→        prev < predictions.length - 1 ? prev + 1 : 0,
182→      );
183→    } else if (e.key === "ArrowUp") {
184→      e.preventDefault();
185→      setActiveIndex((prev) =>
186→        prev > 0 ? prev - 1 : predictions.length - 1,
187→      );
188→    } else if (e.key === "Enter" && activeIndex >= 0) {
189→      e.preventDefault();
190→      selectPrediction(predictions[activeIndex]);
191→    } else if (e.key === "Escape") {
192→      setShowDropdown(false);
193→    }
194→  }
195→
196→  function handleClearLocation() {
197→    setCoords(null);
198→    setLocationLabel(null);
199→    setSearchQuery("");
200→    setSearchError(null);
201→    setPredictions([]);
202→    setShowDropdown(false);
203→    fetchStores();
204→  }
205→
206→  return (
207→    <div className="grid gap-6">
208→      <div className="flex items-baseline justify-between">
209→        <h1 className="text-3xl font-semibold tracking-tight text-[color:var(--lr-ink)]">
210→          Farms
211→        </h1>
212→        {stores && hasLocation ? (
213→          <p className="text-sm text-[color:var(--lr-muted)]">
214→            {stores.length} farm{stores.length !== 1 ? "s" : ""} nearby
215→          </p>
216→        ) : null}
217→      </div>
218→
219→      {isDemo ? (
220→        <div className="flex items-center justify-between rounded-lg border border-amber-300 bg-amber-50 px-4 py-3">
221→          <p className="text-sm font-medium text-amber-800">
222→            Viewing demo stores
223→          </p>
224→          <Link
225→            href="/stores"
226→            className="text-sm font-semibold text-amber-700 underline hover:text-amber-900"
227→          >
228→            Exit demo
229→          </Link>
230→        </div>
231→      ) : null}
232→
233→      {/* Search controls */}
234→      <div ref={wrapperRef} className="relative">
235→      <div className="lr-card lr-card-strong p-4">
236→        <form
237→          onSubmit={handleSubmit}
238→          className="flex flex-wrap items-end gap-3"
239→        >
240→          <div className="grid min-w-[180px] flex-1 gap-1">
241→            <label
242→              htmlFor="location-search"
243→              className="text-xs font-medium text-[color:var(--lr-muted)]"
244→            >
245→              City or zip code
246→            </label>
247→            <input
248→              id="location-search"
249→              type="text"
250→              placeholder="Your city or zip code"
251→              value={searchQuery}
252→              onChange={(e) => handleInputChange(e.target.value)}
253→              onFocus={() => {
254→                if (predictions.length > 0) setShowDropdown(true);
255→              }}
256→              onKeyDown={handleKeyDown}
257→              autoComplete="off"
258→              role="combobox"
259→              aria-expanded={showDropdown}
260→              aria-autocomplete="list"
261→              aria-controls="location-listbox"
262→              aria-activedescendant={
