 36→/* ── helpers ─────────────────────────────────────────────────────── */
 37→
 38→function cadenceLabel(c: string) {
 39→  if (c === "weekly") return "Weekly";
 40→  if (c === "biweekly") return "Every two weeks";
 41→  if (c === "monthly") return "Monthly";
 42→  return c;
 43→}
 44→
 45→function formatDate(iso: string, tz: string) {
 46→  return new Intl.DateTimeFormat("en-US", {
 47→    timeZone: tz || "UTC",
 48→    weekday: "short",
 49→    month: "short",
 50→    day: "numeric",
 51→  }).format(new Date(iso));
 52→}
 53→
 54→function formatTime(iso: string, tz: string) {
 55→  return new Intl.DateTimeFormat("en-US", {
 56→    timeZone: tz || "UTC",
 57→    hour: "numeric",
 58→    minute: "2-digit",
 59→  }).format(new Date(iso));
 60→}
 61→
 62→function formatNext(plan: SubscriptionPlan) {
 63→  const tz = plan.pickup_location.timezone || "UTC";
 64→  const start = new Date(plan.next_start_at);
 65→  return new Intl.DateTimeFormat("en-US", {
 66→    timeZone: tz,
 67→    weekday: "short",
 68→    month: "short",
 69→    day: "numeric",
 70→    hour: "numeric",
 71→    minute: "2-digit",
 72→  }).format(start);
 73→}
 74→
 75→function fullAddress(loc: { address1: string; city: string; region: string; postal_code: string }) {
 76→  return `${loc.address1}, ${loc.city}, ${loc.region} ${loc.postal_code}`;
 77→}
 78→
 79→function mapsDirectionsUrl(address: string) {
 80→  return `https://maps.google.com/maps/dir/?api=1&destination=${encodeURIComponent(address)}`;
 81→}
 82→
 83→function staticMapUrl(lat: number, lng: number) {
 84→  const key = process.env.NEXT_PUBLIC_GOOGLE_MAPS_KEY;
 85→  if (!key) return null;
 86→  return `https://maps.googleapis.com/maps/api/staticmap?center=${lat},${lng}&zoom=14&size=400x250&markers=color:green%7C${lat},${lng}&key=${key}&style=feature:poi|visibility:off`;
 87→}
 88→
 89→/* Group pickup windows by location ID */
 90→type LocationGroup = {
 91→  locationId: string;
 92→  label: string | null;
 93→  address1: string;
 94→  city: string;
 95→  region: string;
 96→  postal_code: string;
 97→  timezone: string;
 98→  lat: number | null;
 99→  lng: number | null;
100→  instructions: string | null;
101→  photo_url: string | null;
102→  windows: PickupWindow[];
103→};
104→
105→function groupByLocation(windows: PickupWindow[]): LocationGroup[] {
106→  const map = new Map<string, LocationGroup>();
107→  for (const pw of windows) {
108→    const loc = pw.pickup_location;
109→    const key = loc.id;
110→    let group = map.get(key);
111→    if (!group) {
112→      group = {
113→        locationId: key,
114→        label: loc.label,
115→        address1: loc.address1,
116→        city: loc.city,
117→        region: loc.region,
118→        postal_code: loc.postal_code,
119→        timezone: loc.timezone,
120→        lat: loc.lat ?? null,
121→        lng: loc.lng ?? null,
122→        instructions: loc.instructions ?? null,
123→        photo_url: loc.photo_url ?? null,
124→        windows: [],
125→      };
126→      map.set(key, group);
127→    }
128→    group.windows.push(pw);
129→  }
130→  return Array.from(map.values());
131→}
132→
