141→
142→  const [storeResult, windowsResult, plansResult, reviewsResult] =
143→    await Promise.allSettled([
144→      api.getStore(storeId),
145→      api.listStorePickupWindows(storeId),
146→      api.listStoreSubscriptionPlans(storeId),
