  1→"use client";
  2→
  3→import { useParams, useRouter } from "next/navigation";
  4→import { useEffect, useState } from "react";
  5→import {
  6→  sellerApi,
  7→  type SellerSubscriptionPlan,
  8→} from "@/lib/seller-api";
  9→import { session } from "@/lib/session";
 10→import { useToast } from "@/components/toast";
 11→import { fieldClass, friendlyErrorMessage } from "@/lib/ui";
 12→import { ImageUpload } from "@/components/seller/image-upload";
 13→
 14→function parseUSDToCents(raw: string): number | null {
 15→  const v = raw.trim();
 16→  if (!v) return 0;
 17→  const n = Number.parseFloat(v);
 18→  if (!Number.isFinite(n)) return null;
 19→  const cents = Math.round(n * 100);
 20→  if (cents < 0) return null;
 21→  return cents;
 22→}
 23→
 24→function toUSDInput(cents: number): string {
 25→  return (cents / 100).toFixed(2);
 26→}
 27→
 28→function defaultFirstPickup(): string {
 29→  const now = new Date();
 30→  const d = new Date(now);
 31→  const targetDow = 6; // Saturday
 32→  const daysAhead = (targetDow - d.getDay() + 7) % 7;
 33→  d.setDate(d.getDate() + daysAhead);
 34→  d.setHours(10, 0, 0, 0);
 35→  if (daysAhead === 0 && now.getTime() >= d.getTime()) d.setDate(d.getDate() + 7);
 36→  const pad2 = (n: number) => String(n).padStart(2, "0");
 37→  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}T${pad2(d.getHours())}:${pad2(d.getMinutes())}`;
 38→}
 39→
 40→type Cadence = "weekly" | "biweekly" | "monthly";
 41→
 42→const CADENCE_OPTIONS: { value: Cadence; label: string }[] = [
 43→  { value: "weekly", label: "Every week" },
 44→  { value: "biweekly", label: "Every 2 weeks" },
 45→  { value: "monthly", label: "Monthly" },
 46→];
 47→
 48→export default function BoxPage() {
 49→  const params = useParams<{ storeId: string }>();
 50→  const storeId = params.storeId;
 51→  const router = useRouter();
 52→  const { showToast, clearToast } = useToast();
 53→
 54→  const [loading, setLoading] = useState(true);
 55→  const [saving, setSaving] = useState(false);
 56→  const [existingPlan, setExistingPlan] = useState<SellerSubscriptionPlan | null>(null);
 57→  const [locationId, setLocationId] = useState<string | null>(null);
 58→
 59→  // Form fields
 60→  const [title, setTitle] = useState("Weekly Farm Box");
 61→  const [description, setDescription] = useState("");
 62→  const [priceUsd, setPriceUsd] = useState("");
 63→  const [cadence, setCadence] = useState<Cadence>("weekly");
 64→  const [subscriberLimit, setSubscriberLimit] = useState(25);
 65→  const [firstStartAt, setFirstStartAt] = useState(defaultFirstPickup);
 66→
 67→  // Validation
 68→  const [touched, setTouched] = useState(false);
 69→  const titleErr = touched && !title.trim();
 70→  const priceErr = touched && (parseUSDToCents(priceUsd) === null || parseUSDToCents(priceUsd) === 0);
 71→  const limitErr = touched && subscriberLimit < 1;
 72→  const dateErr = touched && !firstStartAt;
 73→
 74→  useEffect(() => {
 75→    const token = session.getToken();
 76→    if (!token) {
 77→      router.replace("/seller/login");
 78→      return;
 79→    }
 80→
 81→    let cancelled = false;
 82→
 83→    async function load() {
 84→      try {
 85→        const [locations, plans] = await Promise.all([
 86→          sellerApi.listPickupLocations(token!, storeId),
 87→          sellerApi.listSubscriptionPlans(token!, storeId),
 88→        ]);
 89→
 90→        if (cancelled) return;
 91→
 92→        if (locations.length === 0) {
 93→          router.replace(`/seller/stores/${storeId}/setup/location`);
 94→          return;
 95→        }
 96→
 97→        setLocationId(locations[0].id);
 98→
 99→        if (plans.length > 0) {
100→          const plan = plans.find((p) => p.is_active) ?? plans[0];
101→          setExistingPlan(plan);
102→          setTitle(plan.title);
103→          setDescription(plan.description ?? "");
104→          setPriceUsd(toUSDInput(plan.price_cents));
105→          setCadence(plan.cadence as Cadence);
106→          setSubscriberLimit(plan.subscriber_limit);
107→          // Keep the default first pickup for editing since it's already set on the plan
108→        }
109→      } catch (e: unknown) {
110→        if (!cancelled) {
111→          showToast({ kind: "error", message: friendlyErrorMessage(e) });
112→        }
113→      } finally {
114→        if (!cancelled) setLoading(false);
115→      }
116→    }
117→
118→    load();
119→    return () => {
120→      cancelled = true;
121→    };
122→    // eslint-disable-next-line react-hooks/exhaustive-deps
123→  }, [storeId]);
124→
125→  async function handleSubmit() {
126→    setTouched(true);
127→    clearToast();
128→
129→    const cents = parseUSDToCents(priceUsd);
130→    if (!title.trim() || cents === null || cents <= 0 || subscriberLimit < 1 || !firstStartAt) {
131→      return;
132→    }
133→
134→    const token = session.getToken();
135→    if (!token || !locationId) return;
136→
137→    setSaving(true);
138→    try {
139→      const desc = description.trim() || null;
140→      if (existingPlan) {
141→        await sellerApi.updateSubscriptionPlan(token, storeId, existingPlan.id, {
142→          title: title.trim(),
143→          description: desc,
144→          price_cents: cents,
145→          subscriber_limit: subscriberLimit,
146→        });
147→        showToast({ kind: "success", message: "Box saved." });
148→        router.push(`/seller/stores/${storeId}/setup/payouts`);
149→      } else {
150→        const created = await sellerApi.createSubscriptionPlan(token, storeId, {
151→          pickup_location_id: locationId,
152→          title: title.trim(),
153→          description: desc,
154→          cadence,
155→          price_cents: cents,
156→          subscriber_limit: subscriberLimit,
157→          first_start_at_local: firstStartAt,
158→          duration_minutes: 120,
159→          cutoff_hours: 24,
160→        });
161→        setExistingPlan(created);
162→        showToast({ kind: "success", message: "Box saved. Add a photo below, then continue." });
163→      }
164→    } catch (e: unknown) {
165→      showToast({ kind: "error", message: friendlyErrorMessage(e) });
166→    } finally {
167→      setSaving(false);
168→    }
169→  }
170→
171→  if (loading) {
172→    return (
173→      <div className="flex items-center justify-center py-12">
174→        <div
175→          className="h-6 w-6 rounded-full border-2 border-[color:var(--lr-leaf)] border-t-transparent animate-spin"
176→          role="status"
177→          aria-label="Loading"
178→        />
179→      </div>
180→    );
181→  }
182→
183→  return (
184→    <div className="lr-card lr-animate grid gap-6 p-6 sm:p-8">
185→      <div>
186→        <h1 className="text-xl font-semibold tracking-tight">
187→          Build your first farm box
188→        </h1>
189→        <p className="mt-1 text-sm text-[color:var(--lr-muted)]">
190→          Set up a recurring pickup box for your customers.
191→        </p>
192→      </div>
193→
194→      {/* Box name */}
195→      <label className="grid gap-1">
196→        <span className="text-sm font-medium text-[color:var(--lr-muted)]">
197→          Box name
198→        </span>
199→        <input
200→          className={fieldClass("lr-field px-3 py-2 text-sm", titleErr)}
201→          value={title}
202→          onChange={(e) => setTitle(e.target.value)}
203→          placeholder="e.g. Weekly Farm Box"
204→        />
205→        {titleErr && (
206→          <span className="text-xs text-rose-600">Box name is required.</span>
207→        )}
208→      </label>
209→
210→      {/* Description */}
211→      <label className="grid gap-1">
212→        <span className="text-sm font-medium text-[color:var(--lr-muted)]">
213→          Description
214→        </span>
215→        <textarea
216→          className="lr-field min-h-20 px-3 py-2 text-sm"
217→          value={description}
218→          onChange={(e) => setDescription(e.target.value)}
219→          placeholder="What's in the box? Tell your customers what to expect."
220→        />
221→        <span className="text-xs text-[color:var(--lr-muted)]">
222→          Optional. Shown on your box page.
223→        </span>
224→      </label>
225→
226→      {/* Price */}
227→      <label className="grid gap-1">
228→        <span className="text-sm font-medium text-[color:var(--lr-muted)]">
229→          Price per box
230→        </span>
231→        <div className="relative">
232→          <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-sm text-[color:var(--lr-muted)]">
233→            $
