 11→  region: string;
 12→  slug: string;
 13→  store_count: number;
 14→};
 15→
 16→function matchCity(slug: string, cities: CityEntry[]): CityEntry | null {
 17→  return cities.find((c) => c.slug === slug) ?? null;
 18→}
 19→
 20→type StoreWithNew = Store & { isNew: boolean };
 21→
 22→function storesInCity(stores: Store[], city: CityEntry): StoreWithNew[] {
 23→  const c = city.city.toLowerCase();
 24→  const r = city.region.toLowerCase();
 25→  const now = Date.now();
 26→  const thirtyDays = 30 * 24 * 60 * 60 * 1000;
 27→  return stores
 28→    .filter(
 29→      (s) =>
 30→        s.city?.toLowerCase() === c && s.region?.toLowerCase() === r,
 31→    )
 32→    .map((s) => ({
 33→      ...s,
 34→      isNew: now - new Date(s.created_at).getTime() < thirtyDays,
 35→    }));
 36→}
 37→
 38→function jsonLd(city: CityEntry, stores: Store[]) {
 39→  return {
 40→    "@context": "https://schema.org",
 41→    "@type": "ItemList",
 42→    name: `Local Farms in ${city.city}, ${city.region}`,
 43→    description: `Browse ${stores.length} local farm${stores.length !== 1 ? "s" : ""} offering fresh pickup boxes in ${city.city}, ${city.region}.`,
 44→    numberOfItems: stores.length,
 45→    itemListElement: stores.map((s, i) => ({
 46→      "@type": "ListItem",
 47→      position: i + 1,
 48→      item: {
 49→        "@type": "LocalBusiness",
 50→        "@id": `${process.env.NEXT_PUBLIC_SITE_URL ?? "https://localroots.farm"}/stores/${s.id}`,
 51→        name: s.name,
 52→        ...(s.description ? { description: s.description } : {}),
 53→        ...(s.image_url ? { image: s.image_url } : {}),
 54→        address: {
 55→          "@type": "PostalAddress",
 56→          addressLocality: city.city,
 57→          addressRegion: city.region,
 58→        },
 59→      },
 60→    })),
 61→  };
 62→}
